import{_ as i,o as a,c as e,a3 as n}from"./chunks/framework.aYYe0dfI.js";const o=JSON.parse('{"title":"clore::net::icontains","description":"函数 clore::net::icontains 是一种不区分大小写的子串搜索，通过逐字符比较 haystack 和 needle 实现。实现首先检查 needle.size() > haystack.size()，若成立则直接返回 false，以避免不必要的循环。随后外层循环遍历 haystack 中所有可能的起始位置（i 从 0 到 haystack.size() - needle.size()），内层循环对每个字符对进行不区分大小写的匹配：使用 std::tolower 将两个字符均转为小写后比较。一旦内层循环完全匹配，立即返回 true；否则继续扫描；若所有起始位置都检查完毕未匹配，返回 false。该算法不依赖项目内部工具，仅依赖标准库函数 std::tolower 和 static_cast<unsigned char> 保证字符类型安全。","frontmatter":{"title":"clore::net::icontains","description":"函数 clore::net::icontains 是一种不区分大小写的子串搜索，通过逐字符比较 haystack 和 needle 实现。实现首先检查 needle.size() > haystack.size()，若成立则直接返回 false，以避免不必要的循环。随后外层循环遍历 haystack 中所有可能的起始位置（i 从 0 到 haystack.size() - needle.size()），内层循环对每个字符对进行不区分大小写的匹配：使用 std::tolower 将两个字符均转为小写后比较。一旦内层循环完全匹配，立即返回 true；否则继续扫描；若所有起始位置都检查完毕未匹配，返回 false。该算法不依赖项目内部工具，仅依赖标准库函数 std::tolower 和 static_cast<unsigned char> 保证字符类型安全。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/protocol/functions/icontains.md","filePath":"zh/clore/modules/protocol/functions/icontains.md"}'),t={name:"zh/clore/modules/protocol/functions/icontains.md"};function l(h,s,k,p,d,r){return a(),e("div",null,[...s[0]||(s[0]=[n("",16)])])}const c=i(t,[["render",l]]);export{o as __pageData,c as default};
